import json, urllib.request, struct
from collections import defaultdict

def jpeg_size(data):
    if data[:2] != b'\xff\xd8': return None
    i=2
    while i < len(data):
        if data[i] != 0xff:
            i+=1; continue
        while i < len(data) and data[i]==0xff: i+=1
        if i>=len(data): break
        marker=data[i]; i+=1
        if marker in (0xd8,0xd9): continue
        if i+2>len(data): break
        length=struct.unpack('>H', data[i:i+2])[0]
        if marker in [0xc0,0xc1,0xc2,0xc3,0xc5,0xc6,0xc7,0xc9,0xca,0xcb,0xcd,0xce,0xcf]:
            if i+7 <= len(data):
                h=struct.unpack('>H', data[i+3:i+5])[0]
                w=struct.unpack('>H', data[i+5:i+7])[0]
                return w,h
        i += length
    return None

TAG_CATEGORY_MAP={'CPU':'CPU','메모리':'램','메인보드':'메인보드','그래픽카드':'그래픽카드','SSD':'저장장치','케이스':'케이스','파워서플라이':'파워'}
