@import "styles/variables";
@import "styles/mixins";

.pc-assembly-quote {
  width: 100%;
  padding-top: 0;
  margin-bottom: 0;
  color: $color-text-main;

  *,
  *::before,
  *::after {
    box-sizing: border-box;
  }

  &__title {
    text-align: left;
    font-size: $font-xl;
    font-weight: $font-bold;
    margin: 0 0 12px;
  }

  &__layout {
    display: grid;
    grid-template-columns: repeat(4, minmax(0, 1fr));
    gap: 16px;
    min-width: 0;
  }

  &__list,
  &__compatibility,
  &__total,
  &__right {
    grid-column: 1 / -1;
    min-width: 0;
  }

  &__right {
    display: flex;
    flex-direction: column;
    gap: 16px;
    min-width: 0;
  }

  &__control {
    display: flex;
    justify-content: space-between;
    align-items: center;
    gap: 12px;
    margin-bottom: 12px;
    min-width: 0;
  }

  &__select-all {
    @include flex(center, flex-start);
    gap: 8px;
    min-width: 0;
    font-size: $font-lg;
    font-weight: $font-bold;
    cursor: pointer;

    input {
      position: absolute;
      opacity: 0;
      pointer-events: none;
    }
  }

  &__checkbox-mark {
    @include flex-center;
    width: 22px;
    height: 22px;
    border: 1px solid $color-text-main;
    border-radius: 8px;
    background: $color-white;
    flex-shrink: 0;

    &::after {
      content: "";
      width: 10px;
      height: 5px;
      border-left: 2px solid transparent;
      border-bottom: 2px solid transparent;
      transform: translateY(-1px) rotate(-45deg);
      opacity: 0;
    }
  }

  &__select-all input:checked + &__checkbox-mark {
    background: $color-text-main;

    &::after {
      border-color: $color-white;
      opacity: 1;
    }
  }

  &__delete-button {
    border: 0;
    background: transparent;
    padding: 0;
    font-size: $font-lg;
    font-weight: $font-bold;
    cursor: pointer;
    flex-shrink: 0;
  }

  &__panel {
    @include panel-card();
    display: flex;
    flex-direction: column;
    gap: 10px;
    min-width: 0;
  }

  &__section-title {
    margin: 0 0 12px;
    font-size: $font-lg;
    font-weight: $font-bold;
  }

  &__insights {
    display: flex;
    flex-direction: column;
    gap: 32px;
    min-height: 0;
  }

  &__performance {
    margin-bottom: 0;

    .pc-assembly-quote__panel {
      max-height: 148px;
      overflow-y: auto;
      padding-right: 10px;
      scrollbar-color: $color-category-text transparent;
      scrollbar-width: auto;

      &::-webkit-scrollbar {
        width: 16px;
      }

      &::-webkit-scrollbar-button {
        display: none;
        width: 0;
        height: 0;
      }

      &::-webkit-scrollbar-track {
        background: transparent;
      }

      &::-webkit-scrollbar-thumb {
        background: $color-category-text;
        border-radius: $radius-full;
      }

      &::-webkit-scrollbar-thumb:hover {
        background: $color-category-text;
      }
    }
  }

  &__panel-item {
    display: flex;
    align-items: flex-start;
    gap: 8px;
    min-width: 0;
    color: $color-text-main;
    font-weight: $font-semibold;
    line-height: 1.35;

    .indicator {
      flex: 0 0 auto;
      margin-top: 4px;
    }
  }

  &__panel-empty {
    color: $color-text-muted;
    font-size: $font-sm;
    font-weight: $font-semibold;
  }

  .indicator {
    &--ok {
      @include status-dot(10px, $color-success);
    }
    &--warning {
      @include status-dot(10px, $color-warning);
    }
    &--error {
      @include status-dot(10px, $color-error);
    }
  }

  &__compatibility {
    display: grid;
    grid-template-columns: minmax(0, 1fr) max-content;
    gap: 8px 16px;
    align-items: center;
    background-color: #0aa5a515;
    border-radius: 12px;
    padding: 10px 18px 8px;
    min-width: 0;
  }

  &__compatibility-count {
    @include flex(center, flex-start);
    gap: 8px;
    min-width: 0;
    font-size: $font-md;
    font-weight: $font-bold;
    white-space: nowrap;

    img {
      width: $font-lg;
      height: $font-lg;
      display: block;
    }
  }

  &__compatibility-status {
    grid-column: 1 / -1;
    @include flex(center, flex-start);
    min-width: 0;
    font-size: $font-sm;
    font-weight: $font-semibold;
